mapper.select:
select * from aiw_market_quote
where product_biz_id = #{productBizId} and source_code = #{sourceCode}
  and quote_interval = #{interval} and quote_time = #{quoteTime}

select * from aiw_market_quote
where product_biz_id = #{productBizId} and quote_interval = #{interval}
  and quote_status in (1, 2)
and source_code = #{sourceCode}
order by quote_time desc limit 1

select * from aiw_market_quote
where product_biz_id = #{productBizId} and quote_interval = #{interval}
  and quote_status in (1, 2) and quote_time between #{from} and #{to}
and source_code = #{sourceCode}
order by quote_time asc limit #{limit}

select p.biz_id as product_biz_id, p.product_code, p.product_name, ( select q1.close_price from aiw_market_quote q1 where q1.product_biz_id = p.biz_id and q1.quote_status in (1, 2) and q1.quote_time between #{from} and #{to} order by q1.quote_time asc limit 1 ) as start_price, ( select q2.close_price from aiw_market_quote q2 where q2.product_biz_id = p.biz_id and q2.quote_status in (1, 2) and q2.quote_time between #{from} and #{to} order by q2.quote_time desc limit 1 ) as end_price, ( ( select q3.close_price from aiw_market_quote q3 where q3.product_biz_id = p.biz_id and q3.quote_status in (1, 2) and q3.quote_time between #{from} and #{to} order by q3.quote_time desc limit 1 ) / nullif(( select q4.close_price from aiw_market_quote q4 where q4.product_biz_id = p.biz_id and q4.quote_status in (1, 2) and q4.quote_time between #{from} and #{to} order by q4.quote_time asc limit 1 ), 0) ) - 1 as return_rate from aiw_product p where p.is_deleted = 0 and p.product_code in
#{code}
having start_price is not null and end_price is not null
